var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"관리자님! 오늘 저희 집 마당의 감나무에서 처음으로 감이 떨어졌어요!","JPN":"管理者様！　今日うちの庭の柿の木から、初めて柿が落ちたんです！","ENG":"Administrator! A persimmon finally fell from the tree in our yard today for the very first time!","TWN":"管理者！今天我家院子裡的柿子樹上第一次掉下了柿子！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"보세요. 빨갛게 잘 익었죠?","JPN":"見てください、美味しそうな色でしょう？","ENG":"Look how red and ripe it is. Isn't it pretty?","TWN":"看吧，紅紅的，熟透了吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"인공조경 없이 탁 트인 자연에서 열매가 익어가는 모습을 볼 수 있다는 건 참 좋네요. 관리국의 기상조절장치 시스템이 아니었다면 꿈에서나 봤을 광경이겠죠.","JPN":"人工造園じゃない、開けた自然の中で果実が熟れる様子が見られるって、いいことですね。管理局の気象調整装置がなかったら、こんな景色は夢でしか見られなかったでしょう。","ENG":"It's so nice, seeing fruit ripen in the open air without any artificial landscaping. Without the Administration's Weather Control System, I'd probably never have seen a scene like this outside of a dream.","TWN":"在沒有人工造景的開闊自然中，能看到果實成熟的景象真是太好了。如果不是管理局的氣候調節裝置系統，這種景象恐怕只能在夢中見到吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"앗, 지금 드시면 안 돼요. 이건 잘 말려서 곶감으로 만들 거거든요.","JPN":"あっ、まだ食べてはいけません。これは干し柿にするんです。","ENG":"Ah, don't eat it just yet. I'm planning make them into dried persimmons.","TWN":"啊，現在不能吃喔。這些要晾乾做成柿餅呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"입에 침이 고여도 당분간은 참으셔요. 기다린 보람이 있게 해드릴 테니까.","JPN":"よだれが出ても、しばらく我慢してくださいね。待った甲斐があったと思わせてあげますから。","ENG":"Even if your mouth's watering, try to hold back. I promise it'll be worth the wait.","TWN":"即使口水流出來也請忍耐一會兒。我會讓你覺得等待是值得的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러고보니 절 부르신 용무가 뭐라고 하셨죠?","JPN":"ところで、お呼びになった理由は何でしたか？","ENG":"Oh, right. What did you call me for again?","TWN":"對了，你找我有什麼事？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"음? 저의 몸 상태가 신경 쓰여서…? 아하, 관리자님은 제 몸에 관심이 있으시구나?","JPN":"ん？　私の体の調子が気になって……？　管理者様は、私の体に興味があるんですか？","ENG":"Mm? You were worried about my condition...? So you have been paying attention to my body.","TWN":"嗯？你是在擔心我的身體狀況嗎…？原來管理者對我的身體感興趣啊？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"후후, 농담이에요.","JPN":"ふふ、冗談です。","ENG":"Haha, I'm kidding.","TWN":"呵呵，開玩笑啦。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"사실, 요즘 들어 용혈의 속삭임이 빈번해지고 있긴 하지만 걱정하실 정도는 아니랍니다.","JPN":"実は最近、龍血の囁きが頻繁になってはいるのですが、心配には及びません。","ENG":"Dragon Blood has been whispering a bit more often lately, but it's nothing serious. Nothing to worry about.","TWN":"其實，最近龍血的低語頻繁了些，但還不至於讓人擔心。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"제가 쓰러진다면 그 원인은 용혈이 아니라 스승님의 훈련 강도가 지나쳤기 때문이겠죠.","JPN":"私が倒れるとしたら、原因は龍血ではなくて、きっと師匠の訓練が厳しすぎたせいです。","ENG":"If I collapse, it'll be because my master's training pushed me too far and not Dragon Blood.","TWN":"如果我倒下了，那原因不是龍血，而是師父的訓練強度過高吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"역시 그런 고된 훈련의 스트레스를 견디려면, 보상이 있어야 돼요.","JPN":"やはり、あんなきつい訓練のストレスに耐えるためには、相応のご褒美がないとやっていけません。","ENG":"And if I'm going to survive that kind of brutal training, I need some kind of reward.","TWN":"果然，要承受那種艱苦訓練的壓力，就必須有獎勵才行。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"맛있는 곶감도 좋지만, 제 지쳐가는 심신을 달래 줄 좀 더 정서적인 보상이요.","JPN":"美味しい干し柿もいいですが、疲れ切った心身を慰めてくれる……もう少し精神的なご褒美です。","ENG":"As much as I love dried persimmons, I was thinking of something that could help me unwind.","TWN":"美味的柿餅固然不錯，但我更需要一些能安撫我疲憊身心的情感獎勵。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러니까 저랑 소풍 가요! 풀 냄새 가득한 공원에서 구름 구경하고 도시락도 먹어요!","JPN":"ですから、一緒にピクニックはどうですか？　自然の匂いに包まれた公園で雲を眺めたり、お弁当を食べたりしましょう！","ENG":"So how about a picnic? Let's go to the park, smell the grass, watch the clouds, and share a lunchbox together.","TWN":"所以跟我一起去郊遊吧！在充滿青草香味的公園裡看雲朵，還可以吃便當喔！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러면 내일부턴 훈련도, 검진도, 군말 없이 받을 테니까.","JPN":"つき合ってくださったら、明日から訓練も検診も文句言わずに受けますから。","ENG":"After that, I promise. No complaints about the checkups or the training.","TWN":"那麼從明天開始，我會毫無怨言地接受訓練和檢查。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"협조해주실 거죠?","JPN":"協力してくれますよね？","ENG":"You'll join me, right?","TWN":"你會協助我吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};